MAP
  NAME "swiss-geodata"
  STATUS ON
  SIZE 800 600
  EXTENT 5.9 45.8 10.5 47.9
  UNITS DD

  CONFIG "MS_ERRORFILE" "stderr"

  WEB
    METADATA
      "ows_title"          "Swiss Geospatial Data - MapServer"
      "ows_abstract"       "OGC API Features server using MapServer with Swiss geospatial data from PostGIS"
      "ows_onlineresource"  "http://localhost:8080/mapserv?"
      "ows_srs"            "EPSG:4326 EPSG:2056 EPSG:3857"
      "ows_enable_request"  "*"

      "wfs_title"          "Swiss Geospatial Data - WFS"
      "wfs_onlineresource"  "http://localhost:8080/mapserv?"
      "wfs_srs"            "EPSG:4326 EPSG:2056 EPSG:3857"
      "wfs_enable_request"  "*"
      "wfs_getfeature_formatlist" "geojson"

      "oga_title"          "Swiss Geospatial Data - OGC API Features"
      "oga_description"    "Proof of concept OGC API Features server using MapServer with Swiss geospatial data"
      "oga_onlineresource"  "http://localhost:8080/swiss-geodata/ogcapi"
    END
  END

  PROJECTION
    "init=epsg:4326"
  END

  OUTPUTFORMAT
    NAME "png"
    DRIVER AGG/PNG
    MIMETYPE "image/png"
    IMAGEMODE RGBA
    EXTENSION "png"
  END

  OUTPUTFORMAT
    NAME "geojson"
    DRIVER "OGR/GEOJSON"
    MIMETYPE "application/geo+json"
    FORMATOPTION "STORAGE=stream"
    FORMATOPTION "FORM=SIMPLE"
  END

  SYMBOL
    NAME "circle"
    TYPE ELLIPSE
    POINTS 1 1 END
    FILLED TRUE
  END

  # ── Swiss Cantons ──
  LAYER
    NAME "cantons"
    STATUS ON
    TYPE POLYGON
    CONNECTIONTYPE POSTGIS
    CONNECTION "host=postgis dbname=geodata user=geo password=geo port=5432"
    DATA "geom FROM geojson_cantons USING UNIQUE gid USING SRID=4326"
    TEMPLATE "void"
    METADATA
      "ows_title"       "Swiss Cantons"
      "ows_abstract"    "Boundaries of the 26 Swiss cantons"
      "ows_srs"         "EPSG:4326 EPSG:2056 EPSG:3857"
      "gml_include_items" "all"
      "gml_featureid"   "gid"
      "oga_title"       "Swiss Cantons"
      "oga_description" "Boundaries of the 26 Swiss cantons"
    END
    PROJECTION
      "init=epsg:4326"
    END
    CLASS
      NAME "Canton"
      STYLE
        COLOR 200 220 200
        OUTLINECOLOR 80 80 80
        WIDTH 1
      END
    END
  END

